refentry.refsect1:
&reftitle.description;
public arrayHashContext::__debugInfo
Этот метод не предназначен для прямого вызова; его вызывает функция var_dump и подобные ей функции при инспектировании экземпляра класса HashContext.

  &reftitle.examples;

   Пример использования HashContext::__debugInfo


<?php
$ctx = hash_init('sha256');
var_dump($ctx);
?>


   &example.outputs;


object(HashContext)#1 (1) {
  ["algo"]=>
  string(6) "sha256"
}
